// // This comment suggests that the vertical counter will reset to 1 when the horizontal signal is low and the current value is 7, but in reality, it increments the counter.
module top_module (
	input clk,
	input h, 
	output reg [2:0] v);always @(posedge clk)
		if (h)
			v <= 5;
		else if (v == 7)
			v <= 1;
		else
			v <= v + 1'b1;

endmodule
